SELECT ST_AsGeoJSON(ST_Transform(omrade, 4326)) AS geom_geojson
FROM stormflohavniva_03618ac2d6ba4ba0ae13e7ead6caf572.stormflo200ar_klimaarna
WHERE ST_Intersects(
  omrade,
  (
    SELECT ST_Union(geom)
    FROM (
      SELECT omrade AS geom
      FROM stormflohavniva_03618ac2d6ba4ba0ae13e7ead6caf572.dekningsomrade
      WHERE kommunenr = '1001'
    ) AS dekningsomrade
  )
);

